code.JavaScript:
const readline = require('readline').createInterface({
    input: process.stdin,
    output: process.stdout
});
readline.question('', (n) => {
    n = parseInt(n);
    if (n < 3) console.log('NO');
    else if (n == 3) console.log('YES');
    else if (n > 3) console.log('NO');
    readline.close();
});

